const Q_AGRICULTURE_2020_MODEL_I=[{"id": "objective>Agriculture>2020 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not the role of government in agricultural production? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provision of loans and credits <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">building of storage facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of efficient marketing outlets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of labour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The provision of labour is not a role of government in agricultural production. The government's role in agricultural production includes the provision of loans and credits, building of storage facilities, and establishment of efficient marketing outlets. However, labour provision is typically the responsibility of the individual farmers or farming corporations.</div>", "topic": "ROLES OF GOVERNMENT AND NGOS IN AGRICULTURAL DEVELOPMENT"}, {"id": "objective>Agriculture>2020 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural extension programme would succeed in disseminating new ideas to farmers except if the programme</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is based on research tested on local conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">involves the people for which the programme is planned</div>", "<div style=\"font-family:Cambria;font-size:17px;\">involved only the support to highly trained agricultural extension specialist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is not kept flexible to contemporary technology</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural extension programmes aims at teaching farmers with different methods and with the aids of technology about new farming techniques. <br/> </div>", "topic": "AGRICULTURAL EXTENSION"}, {"id": "objective>Agriculture>2020 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a quality for selecting livestock?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">feed consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">egg production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortality rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">body weight</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mortality rate is not a quality for selecting livestock. It is a statistic that measures the number of deaths in a population, and is not a desirable characteristic when selecting livestock. The other options, such as feed consumption, egg production, and body weight, are all important factors to consider when selecting livestock.</div>", "topic": "ANIMAL HEALTH"}, {"id": "objective>Agriculture>2020 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Investments with long life span in agricultural economics are otherwise known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entrepreneurship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">savings deposit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital can be goods or money used in a business for production and to yield profit over a long Period of time.Capital is a factor of production. <br/> </div>", "topic": "BASIC ECONOMIC PRINCIPLES"}, {"id": "objective>Agriculture>2020 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under normal circumstances, the concept of consumer sovereignty in agriculture implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the consumer and not the farmer determines what to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both the farmer and the consumer determine what to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the consumer and not the farmer owns the means of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the environmental factors determine what to produce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">What to produce is determined by the consumer ,The farmer produce are for the consumer therefore he will only produce what the consumer wants. <br/> </div>", "topic": "BASIC ECONOMIC PRINCIPLES : DEMAND AND SUPPLY"}, {"id": "objective>Agriculture>2020 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A farmer uses his agricultural loans for the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">family use</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hiring machineries and tools</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchasing drugs for livestock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paying for seeds</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural loan can be inform of cash or subsidy ,the aim of such loan is to increase a farmer's Output. <br/> </div>", "topic": "FARM MANAGEMENT : AGRICULTURAL INSURANCE"}, {"id": "objective>Agriculture>2020 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following activities is correct about agricultural extension agent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">teaching farmers the management of exotic breeds of animals and crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">educating farmers on the use of improved inputs and techniques in agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">training school leavers to become professional farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging graduates to take up agriculture as a profession</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural extension agents teach farmers with different methods and with the aids of technology about new farming techniques. <br/> </div>", "topic": "AGRICULTURAL EXTENSION"}, {"id": "objective>Agriculture>2020 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a breed of cattle? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ndama</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sokoto gudali</div>", "<div style=\"font-family:Cambria;font-size:17px;\">white fulani</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sokoto red</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The breeds of cattle listed in the options are Ndama, Sokoto Gudali, White Fulani, and Sokoto Red. Among these, Sokoto Red is not a recognized breed of cattle. The other three are well-known breeds of cattle in Africa.</div>", "topic": "FORMS AND CLASSIFICATION OF MAJOR FARM ANIMALS IN WEST AFRICA"}, {"id": "objective>Agriculture>2020 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following may cause disease in a fish pond? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mixed stocking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor management practices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harvesting</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Poor management practices such as ;pollution of ponds ,use of infected equipments can cause diseases in a fish pond. <br/> </div>", "topic": "FISHERIES AND WILDLIFE : FISH CULTURE SYSTEMS"}, {"id": "objective>Agriculture>2020 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a sign of animal approaching parturition? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soft, pliable and swollen vulva</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relaxed cervix</div>", "<div style=\"font-family:Cambria;font-size:17px;\">full mammary gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drop in milk production <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Animal approaching parturition(act of giving birth) should have an increase in milk production due to  Increase in progesterone and estrogen. <br/> </div>", "topic": "ANIMAL HEALTH : ANIMAL DISEASES"}, {"id": "objective>Agriculture>2020 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The length of oestrus cycle (in days) in goat is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16 - 17</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 - 21</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19 - 20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 - 22</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oestrus cycle, also known as the reproductive cycle, is the period between two consecutive oestrus. In goats, the length of the oestrus cycle is typically 18-21 days.</div>", "topic": "ANIMAL REPRODUCTION"}, {"id": "objective>Agriculture>2020 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Daily management routines in poultry include the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">egg collection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debeaking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water and feed provision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">health care</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Debeaking, beak trimming (also spelt beak-trimming), or beak conditioning is the partial removal of the beak of poultry, <br/> </div>", "topic": "ANIMAL HEALTH"}, {"id": "objective>Agriculture>2020 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a cockerel is castrated, it becomes a <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">broiler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">layer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capon</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a cockerel is castrated, it becomes a capon. Castration in poultry is known as caponization. A capon is a male chicken that has been castrated to improve the quality of its flesh for food and, in some countries like Spain, fattened by a diet of grain.</div>", "topic": "ANIMAL HUSBANDRY"}, {"id": "objective>Agriculture>2020 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following characteristics is not correct of pigs? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prolific animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficient feed converters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">source of meat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">source of land\t</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pigs are known for being prolific animals, efficient feed converters, and a source of meat. However, they are not a source of land. Land is a physical entity in terms of its surface and the resources beneath it, and cannot be sourced from pigs.</div>", "topic": "ANIMAL HUSBANDRY"}, {"id": "objective>Agriculture>2020 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best control ensure for rinderpest disease in cattle is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sanitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vaccination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of antibiotics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eradication of infected stock</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rinderpest disease is a viral disease ,Virus don't die they only become inactive in a non living medium .So the best way to control it is vaccination. <br/> </div>", "topic": "ANIMAL HEALTH"}, {"id": "objective>Agriculture>2020 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not an advantage of drip-irrigation? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertilizers can be applied through the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is reduction in the concentration of salt in the root zone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the system operates on a much lower line pressure than sprinkler system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its efficiency on water distribution in steep slopes is poor</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Drip irrigation is a type of micro-irrigation system that has the potential to save water and nutrients by allowing water to drip slowly to the roots of plants, either from above the soil surface or buried below the surface. The main advantages of drip irrigation are that fertilizers can be applied through the system, there is a reduction in the concentration of salt in the root zone, and the system operates on a much lower line pressure than a sprinkler system. However, its efficiency on water distribution in steep slopes is poor, which is a disadvantage, not an advantage of drip irrigation.</div>", "topic": "CROP HUSBANDRY"}, {"id": "objective>Agriculture>2020 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The windmill is normally used as a source of power in <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pumping well water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ridging\t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erosion control</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Windmill is a machine which translates linear motion of wind to rotational motion by means of adjustable vanes called sails,it's converts wind energy into mechanical energy . <br/> </div>", "topic": "FARM MACHINERY AND IMPLEMENTS : USES AND MAINTENANCE"}, {"id": "objective>Agriculture>2020 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most appropriate farm machinery for breaking soil is the <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">harrow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plough</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ridger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tractor</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most appropriate farm machinery for breaking soil is the plough. A plough is a tool or farm implement used in farming for initial cultivation of soil in preparation for sowing seed or planting. It works by turning over the upper layer of the soil, bringing fresh nutrients to the surface, while burying weeds and the remains of previous crops, allowing them to break down. Therefore, the correct answer is 'plough'.</div>", "topic": "LAND PREPARATION AND SOIL TILLAGE : PRINCIPLES AND PRACTICES"}, {"id": "objective>Agriculture>2020 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the limitation of mechanization of farms is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduction in the cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exposure of soil to the effects of climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in yield of crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction of farm labour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">While mechanization of farms can lead to increased efficiency and productivity, it also has some limitations. One of these is the exposure of soil to the effects of climate. Mechanized farming often involves the use of heavy machinery which can compact the soil, reducing its ability to absorb water and making it more susceptible to erosion. Additionally, the removal of crop residues during mechanized harvesting can leave the soil exposed to wind and water erosion. Therefore, the correct answer is 'exposure of soil to the effects of climate'.</div>", "topic": "MECHANIZATION AND SOURCES OF FARM POWER"}, {"id": "objective>Agriculture>2020 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physical properties of soil include the following except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">PH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moisture content</div>", "<div style=\"font-family:Cambria;font-size:17px;\">. porosity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Physical properties of soil include color, texture, structure, porosity, density, consistence, temperature, and air</div>", "topic": "SOIL FERTILITY"}, {"id": "objective>Agriculture>2020 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not component of soil? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organic matter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">texture</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Texture is a property of soil that describes the proportion of different sized particles in the soil, not a component of soil.</div>", "topic": "SOIL FERTILITY"}, {"id": "objective>Agriculture>2020 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soil nutrient which is important as a constituent of plant proteins and hormones is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur is a nutrient that is important as a constituent of plant proteins and hormones.</div>", "topic": "SOIL FERTILITY"}, {"id": "objective>Agriculture>2020 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the processes of soil formation, the cracks or crevices that are first noticed on the rocks are normally caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the process of soil formation, the cracks or crevices that are first noticed on the rocks are normally caused by temperature. This is due to the process of thermal expansion and contraction. When rocks are exposed to high temperatures, they expand and when the temperature drops, they contract. This continuous process of expansion and contraction causes the rocks to develop cracks or crevices, a process known as thermal weathering.</div>", "topic": "ROCKS AND SOIL FORMATION"}, {"id": "objective>Agriculture>2020 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A soil with the PH range of 6.1 to 6.9 can be described as\t <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkaline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">very acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slightly alkaline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slightly acidic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">pH scale is number 1-14. pH 1-6.9 is acidic ,the closer it is to 1 the more acidic it becomes and the closer it is to 6.9 the less /slightly acidic it becomes ,while  pH7 is rated neutral, while 7.1-12 is rated alkaline. The closer the pH is to 12 the more highly alkaline it gets and the closer it is to pH7.1 the less/slightly alkaline it is.</div>", "topic": "SOIL FERTILITY"}, {"id": "objective>Agriculture>2020 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main purpose of including leguminous crops in pastures is to serve as a source of <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">proteins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vitamins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbohydrates</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main purpose of including leguminous crops in pastures is to serve as a source of proteins. Leguminous crops, such as beans and peas, are known for their high protein content. They also have the ability to fix nitrogen from the atmosphere, which can improve the nutrient content of the soil, making it more fertile for other plants.</div>", "topic": "PASTURE AND FORAGE CROPS"}, {"id": "objective>Agriculture>2020 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not normally a pasture crop? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mucuna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">centrosema</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stylosanthes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">giant star grass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Giant star grass is not normally a pasture crop. Pasture crops are plants that are grown for the purpose of feeding livestock. Mucuna, Centrosema, and Stylosanthes are all examples of pasture crops. Giant star grass, on the other hand, is a type of grass that is often used for ornamental purposes, rather than as a food source for animals.</div>", "topic": "PASTURE AND FORAGE CROPS"}, {"id": "objective>Agriculture>2020 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The damage to the stem of maize plants resulting in hollowness and lodging is most likely caused by <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rodents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grasscutters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stem borers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weevils</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The damage to the stem of maize plants resulting in hollowness and lodging is most likely caused by stem borers. Stem borers are insects that bore into the stem of a plant and feed on its tissues, causing damage and often leading to the plant's death. Rodents and grasscutters can also cause damage to maize plants, but they typically feed on the plant's roots or leaves, not its stem. Weevils, on the other hand, are known for damaging stored grains, not growing plants.</div>", "topic": "CROP PESTS : TYPES"}, {"id": "objective>Agriculture>2020 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common soil mineral found in all crystalline rocks and a main constituent of granite and sandstone is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">biotite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quartz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mica</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quartz is an abundant soil mineral ,It occurs in a variety of forms, both crystalline(in granite) and amorphous(in sandstone). <br/> </div>", "topic": "ROCKS AND SOIL FORMATION : ROCK FORMATION"}, {"id": "objective>Agriculture>2020 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A soil with pH2 can be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moderately acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moderately alkaline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">highly acidic <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">highly alkaline</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">pH scale is number 1-14. pH 1-6.9 is acidic ,the closer it is to 1 the more acidic it becomes and the closer it is to 6.9 the less /slightly acidic it becomes ,while  pH7 is rated neutral, while 7.1-12 is rated alkaline. The closer the pH is to 12 the more highly alkaline it gets and the closer it is to pH7.1 the less/slightly alkaline it is.</div>", "topic": "SOIL FERTILITY"}, {"id": "objective>Agriculture>2020 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will be responsible for the poor yield of fertile soil in a high rainfall area? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leaching of soil nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">very low pH value of land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of soil microbes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high alkalinity of soil</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High rainfall can lead to leaching of soil nutrients, which is the process by which nutrients are washed out of the soil by rain or irrigation. This can lead to a decrease in soil fertility and subsequently, poor yield.</div>", "topic": "SOIL FERTILITY"}, {"id": "objective>Agriculture>2020 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Crop rotation has the following effects on the soil except <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintenance of soil fertility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing concentration of soil pests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improving soil structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predisposing soil to leaching <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation is the growing of different crops in succession on a piece of land to avoid exhausting the soil and to control weeds, pests, and diseases. <br/> </div>", "topic": "CROPPING SYSTEMS, PLANTING PATTERNS AND PLANT DENSITIES"}, {"id": "objective>Agriculture>2020 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of igneous rock?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gneiss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standstone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Igneous rocks are formed from the solidification of magma or lava. The example of igneous rock among the options is granite. Gneiss is a type of metamorphic rock, while limestone and sandstone are types of sedimentary rocks.</div>", "topic": "ROCKS AND SOIL FORMATION"}, {"id": "objective>Agriculture>2020 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A biotic factor influencing agricultural production is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soil structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biotic factors are the living organism like predators ,micro organism,while abiotic factors are the Non living component like sun ,rainfall ,wind etc. <br/> </div>", "topic": "AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS"}, {"id": "objective>Agriculture>2020 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following nutrient element is a macro-nutrient? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phosphorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manganese</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nutrient elements required by plants are classified into two categories: macro-nutrients and micro-nutrients. Macro-nutrients are those elements that are needed in large amounts. Among the options, phosphorus is a macro-nutrient. Zinc, iron, and manganese are micro-nutrients, which are required by plants in smaller amounts.</div>", "topic": "SOIL FERTILITY : MACRO AND MICRO-NUTRIENTS"}, {"id": "objective>Agriculture>2020 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In encouraging farmers to produce more of a particular crop, the Nigerian government has helped farmers in marketing that crop through the establishment of <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rural schools of agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">markets for the sale of crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing boards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural extension offices</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marketing Board can  be defined as an organization set up by a government to regulate the buying and selling of a certain commodity within a specified area.\t <br/> </div>", "topic": "MARKETING OF AGRICULTURAL PRODUCE"}, {"id": "objective>Agriculture>2020 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above shows parts of a plough. <br/> Study it and answer this question. <br/> The part labelled I in the diagram is the <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hitch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">handle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plough share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mould board</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram above is generally a Plough ,A plough or plow is a farm tool for  <br/> loosening or turning the soil before sowing seed or planting. <br/>  part labelled I is the mould board ,it is the curved blade of a plough, which turns over the furrow.A plough may have a wooden, iron or steel frame, with a blade attached to cut and loosen the soil. </div>", "topic": "FARM MACHINERY AND IMPLEMENTS"}, {"id": "objective>Agriculture>2020 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Study the diagram above and answer question <br/> The crop associated with the diagram above is? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Theobroma cacao </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Zingiber officinale </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Hevea brasiliensis </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Gossypium hirsutum </span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Hevea brasiliensis </span>, the Pará rubber tree, sharinga tree, seringueira, or, most commonly, the rubber tree or rubber plant, is a flowering plant belonging to the spurge family Euphorbiaceae. It is the most economically important member of the genus Hevea because the milky latex extracted from the tree is the primary source of natural rubber.</div>", "topic": "CROP HUSBANDRY : CROPS"}, {"id": "objective>Agriculture>2020 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> During which of the following plant propagation methods is the tool represented used? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Seed planting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Seedling transplant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Budding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Layering</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The picture shown above is a bidding knife .A budding knife is a small knife with a type of spatula at the other end of the handle. <br/> Budding, often called bud grafting, is an artificial method of asexual or vegetative propagation in plants. Like grafting, this method is employed to convert one plant (the rootstock) into another plant type with desirable characteristics. Similarly, the resulting plants </div>", "topic": "PLANT PROPAGATION METHODS : ASEXUAL"}, {"id": "objective>Agriculture>2020 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Study the diagram above and answer question <br/> The farm tool associated with the diagram above is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Knife</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secateurs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shears</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cutlass</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tree in this question is a rubber tree and the process depicted is rubber tapping. Rubber tapping is the process by which latex is collected from a rubber tree. The latex is harvested by slicing a groove into the bark of the tree at a depth of one-quarter inch with a hooked knife and peeling back the bark <br/> </div>", "topic": "FARM TOOLS"}, {"id": "objective>Agriculture>2020 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">High relative humidity in a brooder house could lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heat stress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced feed intake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production of dry litter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">build up of pests and diseases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High humidity in a brooder house creates a conducive environment for the growth and multiplication of pests and diseases. It can also lead to the development of mould and fungi, which can be harmful to the chicks.</div>", "topic": "CROP PRODUCTION"}];
